#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>
#include <device_launch_parameters.h>

// Inline timer definitions from timer.h
#include <unistd.h>
#include <stdint.h>
#include <stdlib.h>

__inline__ uint64_t rdtsc() 
{
     uint32_t lo, hi;
     __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
     return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#include <sys/time.h>

struct timeval starttime;
struct timeval endtime;

#define startTime() \
{ \
  gettimeofday(&starttime, 0); \
}
#define stopTime(valusecs) \
{ \
  gettimeofday(&endtime, 0); \
  valusecs = (endtime.tv_sec-starttime.tv_sec)*1000000+endtime.tv_usec-starttime.tv_usec; \
}

// Macro definitions
#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

// Global variables
int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

// CUDA kernel for the pathfinder step
__global__ void pathfinder_step(int* src, int* dst, int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n >= cols) return;

    int min = src[n];
    if (0 < n)
        min = MIN(min, src[n-1]);
    if (cols-1 > n)
        min = MIN(min, src[n+1]);

    dst[n] = wall_row[n] + min;
}

void
init(int argc, char** argv)
{
	if(argc==3){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
	}else{
                printf("Usage: pathfiner width num_of_steps\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; rows > i; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; cols > j; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(const char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

void run(int argc, char** argv);

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src_host, *dst_host, *temp_host;
    int *src_dev, *dst_dev, *wall_dev;
    int min;

    dst_host = result;
    src_host = new int[cols];

    // Allocate device memory
    cudaMalloc(&src_dev, cols * sizeof(int));
    cudaMalloc(&dst_dev, cols * sizeof(int));
    cudaMalloc(&wall_dev, rows * cols * sizeof(int));

    // Copy initial wall data to device
    cudaMemcpy(wall_dev, data, rows * cols * sizeof(int), cudaMemcpyHostToDevice);

    // Initialize src_dev with the first row (wall[0])
    cudaMemcpy(src_dev, wall_dev, cols * sizeof(int), cudaMemcpyDeviceToDevice);

    pin_stats_reset();

    int block_size = 256;
    int num_blocks = (cols + block_size - 1) / block_size;

    for (int t = 0; t < rows-1; t++) {
        // Swap host pointers logic (though we primarily use device memory now)
        // In CUDA, we swap device pointers
        int *temp_dev = src_dev;
        src_dev = dst_dev;
        dst_dev = temp_dev;

        // Launch kernel: compute next row based on current src_dev and wall[t+1]
        // wall row address: wall_dev + (t+1)*cols
        pathfinder_step<<<num_blocks, block_size>>>(src_dev, dst_dev, wall_dev + (t+1)*cols, cols);

        // Check for launch errors
        cudaError_t err = cudaGetLastError();
        if (err != cudaSuccess) {
            fatal(cudaGetErrorString(err));
        }
    }

    // Copy result back to host
    cudaMemcpy(dst_host, dst_dev, cols * sizeof(int), cudaMemcpyDeviceToHost);

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    for (int i = 0; cols > i; i++)
            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; cols > i; i++)
            printf("%d ",dst_host[i]) ;

    printf("\n") ;

#endif

    // Cleanup
    delete [] data;
    delete [] wall;
    delete [] dst_host;
    delete [] src_host;

    cudaFree(src_dev);
    cudaFree(dst_dev);
    cudaFree(wall_dev);
}
